final_template:
AWSTemplateFormatVersion: '2010-09-09'
Description: 'Deploys a CloudWatch Dashboard for analyzing NAT Gateway VPC Flow Logs.'

Parameters:
  DashboardName:
    Type: String
    Default: NATGatewayFlowLogsDashboard
    Description: Name for the CloudWatch Dashboard
  VpcFlowLogsLogGroupName:
    Type: String
    Default: "/aws/vpc/flowlogs/default"
    Description: ARN or name of the CloudWatch Logs group containing VPC Flow Logs for NAT Gateway
    AllowedPattern: '^/aws/vpc/.*'
    ConstraintDescription: Must start with /aws/vpc/
  WidgetTimeRange:
    Type: String
    Default: P7D
    AllowedValues:
      - P1H
      - P3H
      - P12H
      - P1D
      - P3D
      - P7D
      - P14D
      - P30D
    Description: Relative time range for the widgets
  WidgetRefreshInterval:
    Type: String
    Default: 5_MINUTES
    AllowedValues:
      - 1_MINUTE
      - 5_MINUTES
      - 15_MINUTES
      - 30_MINUTES
      - 1_HOUR
      - 3_HOURS
      - 12_HOURS
      - 1_DAY
    Description: Auto-refresh interval for the dashboard widgets

Resources:
  NATGatewayFlowLogsDashboard:
    Type: AWS::CloudWatch::Dashboard
    Properties:
      DashboardName: !Ref DashboardName
      DashboardBody: !Sub |
        {
          "widgets": [
            {
              "type": "logsInsights",
              "properties": {
                "title": "Top 10 Source IPs - Outbound Bytes",
                "queries": [
                  {
                    "id": "q1",
                    "dataSet": "combined",
                    "logGroups": [
                      {
                        "logGroupName": "${VpcFlowLogsLogGroupName}"
                      }
                    ],
                    "queryString": "fields @timestamp, interfaceId, srcAddr, action, bytes | filter interfaceId like /eni-/ | filter action = \"ACCEPT\" | stats sum(bytes) as totalBytes by srcAddr | sort totalBytes desc | limit 10"
                  }
                ],
                "view": {
                  "timeRange": {
                    "relative": {
                      "value": "${WidgetTimeRange}"
                    }
                  },
                  "refreshInterval": "${WidgetRefreshInterval}",
                  "region": "${AWS::Region}"
                }
              },
              "x": 0,
              "y": 0,
              "width": 12,
              "height": 6
            },
            {
              "type": "logsInsights",
              "properties": {
                "title": "Top 10 Source IPs - Outbound Packets",
                "queries": [
                  {
                    "id": "q1",
                    "dataSet": "combined",
                    "logGroups": [
                      {
                        "logGroupName": "${VpcFlowLogsLogGroupName}"
                      }
                    ],
                    "queryString": "fields @timestamp, interfaceId, srcAddr, action, packets | filter interfaceId like /eni-/ | filter action = \"ACCEPT\" | stats sum(packets) as totalPackets by srcAddr | sort totalPackets desc | limit 10"
                  }
                ],
                "view": {
                  "timeRange": {
                    "relative": {
                      "value": "${WidgetTimeRange}"
                    }
                  },
                  "refreshInterval": "${WidgetRefreshInterval}",
                  "region": "${AWS::Region}"
                }
              },
              "x": 12,
              "y": 0,
              "width": 12,
              "height": 6
            },
            {
              "type": "logsInsights",
              "properties": {
                "title": "Top 10 Source IPs - Rejected Packets",
                "queries": [
                  {
                    "id": "q1",
                    "dataSet": "combined",
                    "logGroups": [
                      {
                        "logGroupName": "${VpcFlowLogsLogGroupName}"
                      }
                    ],
                    "queryString": "fields @timestamp, interfaceId, srcAddr, action, packets | filter interfaceId like /eni-/ | filter action = \"REJECT\" | stats sum(packets) as totalPackets by srcAddr | sort totalPackets desc | limit 10"
                  }
                ],
                "view": {
                  "timeRange": {
                    "relative": {
                      "value": "${WidgetTimeRange}"
                    }
                  },
                  "refreshInterval": "${WidgetRefreshInterval}",
                  "region": "${AWS::Region}"
                }
              },
              "x": 0,
              "y": 6,
              "width": 12,
              "height": 6
            },
            {
              "type": "logsInsights",
              "properties": {
                "title": "Top 10 Source IPs - Rejected Bytes",
                "queries": [
                  {
                    "id": "q1",
                    "dataSet": "combined",
                    "logGroups": [
                      {
                        "logGroupName": "${VpcFlowLogsLogGroupName}"
                      }
                    ],
                    "queryString": "fields @timestamp, interfaceId, srcAddr, action, bytes | filter interfaceId like /eni-/ | filter action = \"REJECT\" | stats sum(bytes) as totalBytes by srcAddr | sort totalBytes desc | limit 10"
                  }
                ],
                "view": {
                  "timeRange": {
                    "relative": {
                      "value": "${WidgetTimeRange}"
                    }
                  },
                  "refreshInterval": "${WidgetRefreshInterval}",
                  "region": "${AWS::Region}"
                }
              },
              "x": 12,
              "y": 6,
              "width": 12,
              "height": 6
            }
          ]
        }

Outputs:
  DashboardName:
    Description: Name of the created CloudWatch Dashboard
    Value: !Ref NATGatewayFlowLogsDashboard
  DashboardUrl:
    Description: URL to view the dashboard in the CloudWatch console
    Value: !Sub "https://${AWS::Region}.console.aws.amazon.com/cloudwatch/home?region=${AWS::Region}#dashboards:name=${DashboardName}"

